CREATE TABLE `analytics_events` (
	`id` int AUTO_INCREMENT NOT NULL,
	`campaignId` int NOT NULL,
	`assetId` varchar(255),
	`assetType` varchar(50),
	`eventType` enum('email_open','email_click','link_click','conversion','purchase') NOT NULL,
	`userIdentifier` varchar(255),
	`metadata` json,
	`revenue` decimal(10,2) DEFAULT '0',
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `analytics_events_id` PRIMARY KEY(`id`)
);

CREATE TABLE `campaign_metrics` (
	`id` int AUTO_INCREMENT NOT NULL,
	`campaignId` int NOT NULL,
	`metricDate` date NOT NULL,
	`emailOpens` int DEFAULT 0,
	`emailClicks` int DEFAULT 0,
	`linkClicks` int DEFAULT 0,
	`conversions` int DEFAULT 0,
	`revenue` decimal(10,2) DEFAULT '0',
	`spend` decimal(10,2) DEFAULT '0',
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	`updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
	CONSTRAINT `campaign_metrics_id` PRIMARY KEY(`id`),
	CONSTRAINT `unique_campaign_date` UNIQUE(`campaignId`,`metricDate`)
);

ALTER TABLE `analytics_events` ADD CONSTRAINT `analytics_events_campaignId_campaigns_id_fk` FOREIGN KEY (`campaignId`) REFERENCES `campaigns`(`id`) ON DELETE cascade ON UPDATE no action;

ALTER TABLE `campaign_metrics` ADD CONSTRAINT `campaign_metrics_campaignId_campaigns_id_fk` FOREIGN KEY (`campaignId`) REFERENCES `campaigns`(`id`) ON DELETE cascade ON UPDATE no action;

CREATE INDEX `idx_analytics_campaign` ON `analytics_events` (`campaignId`);
CREATE INDEX `idx_analytics_asset` ON `analytics_events` (`assetId`);
CREATE INDEX `idx_analytics_eventType` ON `analytics_events` (`eventType`);
CREATE INDEX `idx_analytics_createdAt` ON `analytics_events` (`createdAt`);
CREATE INDEX `idx_campaignMetrics_date` ON `campaign_metrics` (`metricDate`);

